// renderUltraWide renders 4 panels side-by-side
// System, Network, Token, and TMUX panels
func (d *Dashboard) renderUltraWide() string {
	// Account for panel padding (0,1) which adds 2 chars per panel = 8 total
	totalPanelWidth := d.width - 8
	panelHeight := d.height - 3 // -2 borders, -1 status line

	// Fixed widths for system and network panels
	systemWidth := 55
	networkWidth := 50

	// Available space for token and tmux panels
	availableWidth := totalPanelWidth - systemWidth - networkWidth

	// Calculate minimum and ideal widths for token and tmux panels
	minTokenWidth := 46
	minTmuxWidth := d.calculateTmuxPanelWidth(panelHeight)

	idealTokenWidth := 60
	idealCellWidth := 35
	tmuxCols := d.getTmuxColumnCount(panelHeight)
	idealTmuxWidth := tmuxCols*idealCellWidth + (tmuxCols - 1) + 4

	// Start with minimums
	tokenWidth := minTokenWidth
	tmuxWidth := minTmuxWidth

	// Calculate how much each panel wants beyond minimum
	tokenWant := idealTokenWidth - minTokenWidth
	if tokenWant < 0 {
		tokenWant = 0
	}
	tmuxWant := idealTmuxWidth - minTmuxWidth
	if tmuxWant < 0 {
		tmuxWant = 0
	}

	// Distribute remaining space proportionally based on wants
	remainingAfterMins := availableWidth - minTokenWidth - minTmuxWidth
	if remainingAfterMins > 0 {
		totalWant := tokenWant + tmuxWant
		if totalWant > 0 {
			// Proportional allocation
			tokenExtra := remainingAfterMins * tokenWant / totalWant
			tmuxExtra := remainingAfterMins - tokenExtra
			tokenWidth = minTokenWidth + tokenExtra
			tmuxWidth = minTmuxWidth + tmuxExtra
		} else {
			// Neither wants more, split evenly
			tokenWidth = minTokenWidth + remainingAfterMins/2
			tmuxWidth = minTmuxWidth + remainingAfterMins - remainingAfterMins/2
		}
	} else if remainingAfterMins < 0 {
		// Not enough space for both minimums - compress proportionally
		deficit := -remainingAfterMins
		totalMin := minTokenWidth + minTmuxWidth
		// Reduce each panel proportionally to its minimum
		tokenReduction := deficit * minTokenWidth / totalMin
		tmuxReduction := deficit - tokenReduction
		tokenWidth = minTokenWidth - tokenReduction
		tmuxWidth = minTmuxWidth - tmuxReduction
		// Enforce absolute minimums
		if tokenWidth < 30 {
			tokenWidth = 30
			tmuxWidth = availableWidth - tokenWidth
		}
		if tmuxWidth < 30 {
			tmuxWidth = 30
			tokenWidth = availableWidth - tmuxWidth
		}
	}

	// Cap token panel - it doesn't need more than ideal
	if tokenWidth > idealTokenWidth {
		excess := tokenWidth - idealTokenWidth
		tokenWidth = idealTokenWidth
		tmuxWidth += excess
	}

	// Final safety: ensure widths are positive
	if tokenWidth < 1 {
		tokenWidth = 1
	}
	if tmuxWidth < 1 {
		tmuxWidth = 1
	}

	systemPanel := d.renderSystemPanel(systemWidth, panelHeight)
	networkPanel := d.renderNetworkPanel(networkWidth, panelHeight)
	tokenPanel := d.renderTokenPanel(tokenWidth, panelHeight)
	tmuxPanel := d.renderTmuxPanel(tmuxWidth, panelHeight)

	// Force all panels to exactly the same height using lipgloss
	// This ensures borders align even if content varies
	uniformHeight := lipgloss.NewStyle().Height(panelHeight)
	systemPanel = uniformHeight.Render(systemPanel)
	networkPanel = uniformHeight.Render(networkPanel)
	tokenPanel = uniformHeight.Render(tokenPanel)
	tmuxPanel = uniformHeight.Render(tmuxPanel)

	// Join horizontally with top alignment
	return lipgloss.JoinHorizontal(lipgloss.Top,
		systemPanel,
		networkPanel,
		tokenPanel,
		tmuxPanel,
	)
}

